INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer) VALUES
('D1', '2026年1月1日起正式实施的《中国人身保险业经验生命表（2025）》（第四套生命表），与上一版相比，以下哪项说法正确？', '人口平均预期寿命缩短，定期寿险费率将上升', '人口死亡率下降约20%，养老年金险费率预计上涨5%-15%', '新生命表仅影响健康险定价，对寿险产品无影响', '男性平均预期寿命增幅大于女性', 'B'),
('D1', '根据2026年2月1日实施的《金融机构产品适当性管理办法》，以下哪种情况投保人需额外签署投保声明？', '购买意外险时趸交保费超过家庭年收入2倍', '购买分红险时年交保费超过家庭年收入20%', '购买定期寿险时缴费年限与年龄之和≥75', '购买医疗险时保费额度超过预算150%', 'B'),
('D1', '关于保险行业科技伦理，以下哪项做法符合当前监管倡导的方向？', '为提升风控精度，可未经客户授权采集其社交关系数据', 'AI核保模型产生拒保结论后，无需向客户解释具体原因', '保险科技应用应坚持"以客户利益为中心"，确保算法公平透明', '利用AI自动续保功能，无需客户确认即可完成续费扣款', 'C'),
('D1', '2026年保险行业"非车险报行合一"政策全面显现，以下哪项是其核心要求？', '保险公司可以灵活调整已备案条款费率以提升市场竞争力', '保险公司必须严格执行向监管备案的条款和费率', '非车险产品统一实行"先出单、后缴费"模式', '允许保险公司以返佣方式促进非车险销售', 'B');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer) VALUES
('D2', '香农将热力学中的熵引入信息论，关于熵与信息的关系，以下说法正确的是？', '熵是系统有序程度的度量，信息是系统无序程度的度量', '熵是系统无序程度的度量，信息是系统有序程度的度量（表现为负熵）', '熵和信息都是系统无序程度的度量', '熵和信息都是系统有序程度的度量', 'B'),
('D2', '我国新型基础设施建设分为三大类别，以下哪项属于"融合基础设施"？', '人工智能算力平台', '5G通信网络', '智能交通基础设施', '重大科技基础设施', 'C'),
('D2', '信息系统生命周期通常分为五个阶段，其中"需求分析"属于哪个阶段？', '系统规划', '系统分析', '系统设计', '系统实施', 'B'),
('D2', '在软件工程中，敏捷开发方法与瀑布模型的核心区别是？', '敏捷开发不需要编写文档', '瀑布模型支持需求变更，敏捷开发不支持', '敏捷开发强调迭代增量交付和快速响应需求变更', '敏捷开发不需要测试环节', 'C'),
('D2', 'IT服务管理（ITSM）中，问题管理与事件管理的核心区别是？', '事件管理关注根本原因，问题管理关注快速恢复', '事件管理关注快速恢复正常服务，问题管理关注查找根本原因以防止再次发生', '两者职责完全相同，只是名称不同', '问题管理只处理硬件故障，事件管理只处理软件故障', 'B'),
('D2', '关于关系型数据库与NoSQL数据库，以下说法正确的是？', '关系型数据库不支持事务处理', 'NoSQL数据库统一采用SQL语言进行查询', '关系型数据库使用表格组织数据并通过外键建立关系，支持ACID事务', 'NoSQL数据库完全取代了关系型数据库的应用场景', 'C'),
('D2', '车联网（IoV）系统采用"端、管、云"三层体系，其中"管系统"的核心功能是？', '采集车辆传感数据，感知行车状态', '解决车与车、车与路、车与网、车与人的互联互通', '汇聚多源海量信息，提供云计算服务', '管理车辆生产制造流程', 'B'),
('D2', '信息系统审计中，以下哪项不属于COBIT框架的核心治理目标？', '确保IT与业务战略对齐', '保证系统开发进度永远不延期', '有效管理IT风险', '确保IT资源的高效利用', 'B');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer) VALUES
('D3', '2026年法国FICOBA银行账户数据泄露事件暴露了120万条敏感信息，该事件最严重的衍生风险是？', '数据库服务器宕机导致业务中断', '泄露数据被用于社会工程学攻击，构建精准诈骗链', '网站首页被篡改', '员工办公电脑感染病毒', 'B'),
('D3', '关于深度伪造（Deepfake）技术带来的安全威胁，以下说法最准确的是？', '深伪技术只能用于制作娱乐视频，不构成安全威胁', '攻击者可利用深伪音视频冒充可信人员，诱骗员工转移资金或泄露信息', '深伪技术仅威胁个人隐私，对企业安全无影响', '现有技术已能100%识别所有深伪内容', 'B'),
('D3', '关于密码管理与量子安全，以下做法最符合2026年安全趋势？', '继续使用RSA-2048等传统加密算法，量子计算尚需多年才成熟', '企业应立即识别敏感数据加密方案中的漏洞，规划向后量子加密迁移', '量子计算威胁仅影响政府部门，企业无需关注', '将所有加密算法替换为最长密钥的传统算法即可应对量子威胁', 'B'),
('D3', '以下哪种场景最可能导致内部数据泄露？', '定期开展安全意识培训和模拟钓鱼演练', '员工将含敏感数据的报表通过个人邮箱发送给外部合作方', '使用企业VPN远程接入内网办公', '启用多因素认证（MFA）登录核心系统', 'B');
INSERT INTO questions (dimension, content, option_a, option_b, option_c, option_d, correct_answer) VALUES
('D4', '2026年被视为"AI智能体元年"，关于AI智能体在保险行业的应用，以下说法最准确的是？', 'AI智能体可完全自主处理理赔，无需人工介入', 'AI智能体可自主感知环境、调用工具完成复杂任务，但仍需人机协同确保决策可靠性', 'AI智能体仅能用于客服聊天场景', 'AI智能体不具备与第三方系统对接的能力', 'B'),
('D4', '在保险行业AI应用中，"大小模型协同"模式的优势是？', '只用大模型即可解决所有问题，无需小模型', '大模型擅长语言理解和推理，小模型擅长结构化信息判别决策，二者协同实现更优效果', '小模型完全替代大模型，降低成本', '大小模型必须部署在同一台服务器上才能协同', 'B'),
('D4', '关于2026年云原生技术趋势，以下说法正确的是？', 'Kubernetes正在从容器编排工具向云原生操作系统演进，Wasm容器在边缘计算领域崭露头角', '微服务架构应尽可能细粒度拆分，服务越多越好', 'Serverless技术已被淘汰，企业回归传统部署模式', 'DevSecOps是将安全测试放在开发最后阶段统一执行', 'A'),
('D4', '某保险公司采用大数据风控建模优化反欺诈能力，以下关于特征工程的理解最准确的是？', '特征工程就是收集尽可能多的原始数据，数据量越大模型越好', '特征工程是从原始数据中提取、构造对模型预测有效的高质量特征，是提升模型性能的关键步骤', '特征工程可以完全由AI自动完成，无需人工参与', '特征工程只在模型训练阶段有效，对推理阶段无影响', 'B');
